1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
33	type Customer = { yearsWithMHPCO: number };
34	type Damage = { itemType: string; amount: number };
35	type Incident = { cause: string; damages: Damage[] };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
38	type Step = QuoteStep | ClaimStep;
39	type Scenario = { customer: Customer; steps: Step[] };
40	type QuoteResult = { premium: number };
41	type ClaimResult = { payout: number; remainingCap: number };
42	type StepResult = QuoteResult | ClaimResult;
43	
44	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
45	
46	const enchantmentLevelOf = (item: Item): number => item.enchantment ?? 0;
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const BLOCK_SIZE = 3;
50	const BLOCK_BASE_PREMIUM = 60;
51	
52	const sumBasePremiums = (items: Item[]): number =>
53	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
54	
55	const componentGroupSubtotalOf = (group: Item[]): number =>
56	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
57	
58	const groupByType = (items: Item[]): Item[][] => {
59	  const groups = new Map<string, Item[]>();
60	  for (const item of items) {
61	    const group = groups.get(item.type);
62	    if (group) {
63	      group.push(item);
64	    } else {
65	      groups.set(item.type, [item]);
66	    }
67	  }
68	  return [...groups.values()];
69	};
70	
71	const componentSubtotalOf = (components: Item[]): number =>
72	  groupByType(components).reduce(
73	    (sum, group) => sum + componentGroupSubtotalOf(group),
74	    0,
75	  );
76	
77	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
78	
79	const policyBaseOf = (items: Item[]): number => {
80	  const components = items.filter(isComponent);
81	  const standaloneItems = items.filter((item) => !isComponent(item));
82	  return sumBasePremiums(standaloneItems) + componentSubtotalOf(components);
83	};
84	
85	const firstInsuranceSurchargeOf = (policyBase: number): number =>
86	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
87	
88	const cursedSurchargeOf = (item: Item): number =>
89	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
90	
91	const highEnchantmentSurchargeOf = (item: Item): number =>
92	  enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_THRESHOLD
93	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
94	    : 0;
95	
96	const itemSurchargeOf = (item: Item): number =>
97	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
98	
99	const itemSurchargesOf = (items: Item[]): number =>
100	  items.reduce((sum, item) => sum + itemSurchargeOf(item), 0);
101	
102	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
103	
104	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
105	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
106	
107	const followUpDiscountOf = (policyBase: number, isFollowUp: boolean): number =>
108	  isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
109	
110	const policySurchargesOf = (policyBase: number): number =>
111	  firstInsuranceSurchargeOf(policyBase);
112	
113	const policyDiscountsOf = (
114	  policyBase: number,
115	  customer: Customer,
116	  isFollowUp: boolean,
117	): number =>
118	  loyaltyDiscountOf(policyBase, customer) + followUpDiscountOf(policyBase, isFollowUp);
119	
120	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
121	  const policyBase = policyBaseOf(items);
122	  const surcharges = itemSurchargesOf(items) + policySurchargesOf(policyBase);
123	  const discounts = policyDiscountsOf(policyBase, customer, isFollowUp);
124	  const rawPremium = policyBase + surcharges - discounts + PROCESSING_FEE;
125	  return roundUpInMHPCOFavor(rawPremium);
126	};
127	
128	const isFollowUpContract = (stepIndex: number): boolean => stepIndex > 0;
129	
130	const insuranceSumOf = (items: Item[]): number =>
131	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
132	
133	const reimbursableDamageOf = (damage: Damage, insuredItem: Item): number =>
134	  enchantmentLevelOf(insuredItem) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
135	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : damage.amount;
137	
138	const damagePayoutOf = (damage: Damage, insuredItem: Item): number =>
139	  reimbursableDamageOf(damage, insuredItem) - DEDUCTIBLE;
140	
141	const findInsuredItem = (itemType: string, items: Item[]): Item =>
142	  items.find((item) => item.type === itemType) as Item;
143	
144	const incidentPayoutOf = (incident: Incident, policyItems: Item[]): number =>
145	  incident.damages.reduce(
146	    (sum, damage) => sum + damagePayoutOf(damage, findInsuredItem(damage.itemType, policyItems)),
147	    0,
148	  );
149	
150	const policyCapOf = (policyItems: Item[]): number =>
151	  insuranceSumOf(policyItems) * CAP_MULTIPLIER;
152	
153	const originatingQuoteOf = (claimStep: ClaimStep, scenario: Scenario): QuoteStep =>
154	  scenario.steps[claimStep.policy] as QuoteStep;
155	
156	const processClaim = (claimStep: ClaimStep, scenario: Scenario): ClaimResult => {
157	  const policyItems = originatingQuoteOf(claimStep, scenario).items;
158	  const payout = incidentPayoutOf(claimStep.incident, policyItems);
159	  const cap = policyCapOf(policyItems);
160	  return { payout, remainingCap: cap - payout };
161	};
162	
163	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
164	  const results: StepResult[] = scenario.steps.map((step, index) => {
165	    if (step.op === "quote") {
166	      return {
167	        premium: quotePremium(step.items, scenario.customer, isFollowUpContract(index)),
168	      };
169	    }
170	    return processClaim(step, scenario);
171	  });
172	  return { results };
173	};
